#include<cstdio>
#include<vector>
#include<algorithm>
#include<cstring>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
typedef long long LL;
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
const int N=5e5+10,Mod=1e9+7;int fa[N],siz[N],n,P[N];inline int fnd(int x){return fa[x]==x?x:fa[x]=fnd(fa[x]);}
int pm[N>>2],cpt,Inv[N],a[N];bool vs[N];int cnt[N],f1[N],f2[N],tot,ans;inline void DN(int &x){x>=Mod?x-=Mod:0;}
struct Pair{int x,y;inline Pair(const int &X=0,const int &Y=0){x=X;y=Y;}};std::vector<Pair> Pm[N];
inline int qpow(int a,int b=Mod-2){int r(1);while(b)b&1?r=1ll*r*a%Mod:0,a=1ll*a*a%Mod,b=b>>1;return r;}
inline void Init(const int &W=500000)
{
	vs[1]=true;rep(2,W,i){if(!vs[i])pm[++cpt]=i;for(int j=1;j<=cpt&&pm[j]*i<=W;++j){vs[pm[j]*i]=true;if(i%pm[j]==0)break;}}
	rep(1,cpt,i){const int &p=pm[i];Inv[i]=qpow(p);for(int j=p;j<=W;j+=p){int t=j,s=0;while(t%p==0)++s,t/=p;;Pm[j].push_back(Pair(i,s));}}
	
}
inline void Solve()
{
	n=read();rep(1,n,i)siz[fa[i]=i]=1;memset(cnt,0,(n+5)<<2);ans=0;tot=0;memset(f1,0,(n+5)<<2);memset(f2,0,(n+5)<<2);
	rep(1,n,i){P[i]=read();int x=fnd(i),y=fnd(P[i]);if(x==y)continue;fa[x]=y;siz[y]+=siz[x];} 
	rep(1,n,i)if(fa[i]==i)++cnt[a[++tot]=siz[i]];std::sort(a+1,a+tot+1);tot=std::unique(a+1,a+tot+1)-a-1;
	rep(1,tot,i)for(Pair v:Pm[a[i]]){if(v.y>f1[v.x]){f2[v.x]=(cnt[a[i]]>1)?v.y:f1[v.x];f1[v.x]=v.y;}else if(v.y>f2[v.x])f2[v.x]=v.y;}
	rep(1,tot,i)rep(i+(cnt[a[i]]==1),tot,j)
	{
		int num=(i==j?1ll*cnt[a[i]]*(cnt[a[i]]-1):2ll*cnt[a[i]]*cnt[a[j]])%Mod*a[i]%Mod*a[j]%Mod;
		for(Pair v:Pm[a[i]])if(v.y==f1[v.x])num=1ll*num*qpow(Inv[v.x],f1[v.x]-f2[v.x])%Mod;
		for(Pair v:Pm[a[j]])if(v.y==f1[v.x])num=1ll*num*qpow(Inv[v.x],f1[v.x]-f2[v.x])%Mod;
		for(Pair v:Pm[a[i]+a[j]])if(v.y>f1[v.x])num=1ll*num*qpow(pm[v.x],v.y-f1[v.x])%Mod;DN(ans+=num);
	}
	rep(1,cpt,i)ans=1ll*ans*qpow(pm[i],f1[i])%Mod;printf("%d\n",ans);
}
int main(){Init();int T=read();while(T--)Solve();}
